import React from 'react';

export default function SafetyDisclaimer(){
  return (
    <div style={{background:'#fff7f7',padding:12,border:'1px solid #ffd6d6',marginBottom:12}}>
      <strong>Safety notice:</strong> This assistant is for educational/preliminary support only and is not a substitute for professional medical advice. In emergencies, contact local emergency services.
    </div>
  )
}
